use core::mem;
struct MemoryPool {
    buffer: [u8; 4096],
    next_free: usize,
}

impl MemoryPool {
    fn new() -> Self {
        MemoryPool {
            buffer: [0; 4096],
            next_free: 0,
        }
    }

    fn allocate<T>(&mut self) -> Option<*mut T> {
        let size = mem::size_of::<T>();
        if self.next_free + size > self.buffer.len() {
            return None;
        }
        let ptr = unsafe { self.buffer.as_mut_ptr().add(self.next_free) as *mut T };
        self.next_free += size;
        Some(ptr)
    }

    unsafe fn deallocate(&mut self, _ptr: *mut u8, _size: usize) {


    }
}

fn main() {
    let mut pool = MemoryPool::new();
    unsafe {
        let map_ptr = pool.allocate::<[[u8; 4] ; 10]>().unwrap();
        println!("Successfully allocated space for a complex structure at {:p}", map_ptr);

        let list_item_ptr = pool.allocate::<u32>().unwrap();
        *list_item_ptr = 0xDEADBEEF;
        println!("Successfully wrote value to another location at {:p}", list_item_ptr);
    }
}

use std::collections::HashMap;
use std::sync::Once;

struct VaultManager {
    vault_data: HashMap<u32, Vec<u8>>,
    owner_map: HashMap<String, Vec<u32>>,
}

impl VaultManager {
    fn new() -> Self {
        VaultManager { 
            vault_data: HashMap::new(), 
            owner_map: HashMap::new() 
        }
    }

    fn add_record(&mut self, owner_id: &str, record_id: u32, encrypted_payload: Vec<u8>) {
        self.vault_data.insert(record_id, encrypted_payload);
        self.owner_map.entry(owner_id.to_string()).or_default().push(record_id);
    }

    fn get_records_for_owner(&self, owner_id: &str) -> Option<&Vec<u32>> {
        self.owner_map.get(owner_id)
    }
}

fn main() {
    let mut manager = VaultManager::new();
    manager.add_record("alice", 101, vec![1, 2, 3]);
    manager.add_record("bob", 205, vec![4, 5, 6]);
    manager.add_record("alice", 102, vec![7, 8, 9]);

    if let Some(ids) = manager.get_records_for_owner("alice") {
        println!("Found {} records for Alice: {:?}", ids.len(), ids);
    }
}

use std::time::{Instant, Duration};

struct SimpleRateLimiter {
    last_request_time: Instant,
    limit_duration: Duration,
}

impl SimpleRateLimiter {
    fn new() -> Self {
        SimpleRateLimiter {
            last_request_time: Instant::now(),
            limit_duration: Duration::from_secs(1),
        }
    }

    fn try_acquire(&mut self) -> bool {
        let now = Instant::now();
        if now.duration_since(self.last_request_time) >= self.limit_duration {
            self.last_request_time = now;
            true
        } else {
            false
        }
    }
}

fn main() {
    let mut limiter = SimpleRateLimiter::new();
    println!("Attempt 1: {}", limiter.try_acquire());
    std::thread::sleep(Duration::from_millis(500));
    println!("Attempt 2 (should fail): {}", limiter.try_acquire());
    std::thread::sleep(Duration::from_secs(1));
    println!("Attempt 3 (should pass): {}", limiter.try_acquire());
}

use core::mem::MaybeUninit;
extern crate alloc;
use alloc::vec::Vec;
use std::ptr;

struct Particle {
    id: u32,
    x: f32,
    y: f32,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut particle_storage: Vec<Particle> = Vec::new();
    let initial_particles = vec![
        Particle { id: 1, x: 0.0, y: 1.0 },
        Particle { id: 2, x: 1.0, y: 0.5 },
    ];

    for particle in initial_particles {
        particle_storage.push(particle);
    }

    println!("Initial count: {}", particle_storage.len());

    let new_particle = Particle { id: 3, x: -1.0, y: 2.0 };
    unsafe {
        particle_storage.push(new_particle);
    }

    println!("Final count: {}", particle_storage.len());

    Ok(())
}

use std::collections::VecDeque;

struct SlidingWindowTracker {
    window: VecDeque<f64>,
    capacity: usize,
}

impl SlidingWindowTracker {
    fn new(capacity: usize) -> Self {
        SlidingWindowTracker {
            window: VecDeque::with_capacity(capacity),
            capacity,
        }
    }

    fn add_value(&mut self, value: f64) {
        self.window.push_back(value);
        if self.window.len() > self.capacity {
            self.window.pop_front();
        }
    }

    fn calculate_mean(&self) -> Option<f64> {
        if self.window.is_empty() {
            return None;
        }
        let sum: f64 = self.window.iter().sum();
        Some(sum / (self.window.len() as f64))
    }

    fn calculate_stddev(&self) -> Option<f64> {
        let mean = self.calculate_mean()?;
        if self.window.len() < 2 {
            return Some(0.0);
        }
        let variance: f64 = self.window.iter().map(|&val| (val - mean).powi(2)).sum();
        Some((variance / ((self.window.len() - 1) as f64)).sqrt()) 
    }

    fn get_z_score(&self, current_value: f64) -> Option<f64> {
        let mean = self.calculate_mean()?;
        let stddev = self.calculate_stddev()?;
        if stddev == 0.0 {
            return Some(0.0);
        }
        Some((current_value - mean) / stddev)
    }
}

fn main() {
    let mut tracker = SlidingWindowTracker::new(10);

    tracker.add_value(10.0);
    tracker.add_value(11.0);
    tracker.add_value(9.5);

    if let Some(z) = tracker.get_z_score(25.0) {
        println!("Z-Score for 25.0: {}", z);
    }

    tracker.add_value(10.5); // This should push out the original 10.0 if capacity was exactly 3, but we track more.
    if let Some(z) = tracker.get_z_score(12.0) {
        println!("Z-Score for 12.0: {}", z);
    }
}
